mapper.sql:
/* wms-inbound-iborderreport-sql-oracle.xml - selectIbOrderDetailsql - 입고현황 - 주문별 현황 - 입고 주문 상세 조회 SQL */ WITH BASE AS ( SELECT B.IBEXPCTDATE AS 입고예정일자 , B.IBHDTYPECD AS 입고유형 , B.IBHDKEY AS 입고번호 , A.IBDTKEY , COALESCE(C.MASICYN, 'N') AS 모자 , COALESCE(A.EXPCTQTY, 0) AS EXPCTQTY , COALESCE(A.IBQTY, 0) AS IBQTY , COALESCE(A.CNFRMQTY, 0) AS CNFRMQTY , COALESCE(A.CPAMT, 0) AS UNIT_AMT , COALESCE(A.EXPCTQTY * A.CPAMT, 0) AS PLAN_AMT , COALESCE(A.IBQTY * A.CPAMT, 0) AS IB_AMT , COALESCE(A.CNFRMQTY * A.CPAMT, 0) AS CNFM_AMT , COALESCE(A.UPDATEDATE, '00000000') AS UPDATEDATE FROM TWORK_INFO_IB_DT A JOIN TWORK_INFO_IB_HD B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.IBHDKEY = B.IBHDKEY JOIN TWORK_MST_IC C ON A.CTKEY = C.CTKEY AND A.OWKEY = C.OWKEY AND A.ICKEY = C.ICKEY WHERE A.CTKEY = #{ctkey} AND A.OWKEY = #{owkey} AND B.IBEXPCTDATE = #{ibexpctdate} ) SELECT MAX(입고예정일자) ibexpctdate, (SELECT CTCDDTNM FROM TWORK_MST_CTCD_DT WHERE CTCDHDKEY='IBHDTYPECD' AND CTCDDTVAL = 입고유형 ) AS OB_CTNM, /* ===== 입고예정 PLAN ===== */ COALESCE(SUM(CASE WHEN 모자='Y' THEN (CASE WHEN EXPCTQTY>0 THEN 1 END) END), 0) AS planSkuMother, COALESCE(SUM(CASE WHEN 모자='N' THEN (CASE WHEN EXPCTQTY>0 THEN 1 END) END), 0) AS planSkuChild, COALESCE(SUM(EXPCTQTY), 0) AS planEa, COALESCE(SUM(PLAN_AMT), 0) AS planAmt, /* ===== 입하 IB ===== */ COALESCE(SUM(CASE WHEN 모자='Y' THEN (CASE WHEN IBQTY>0 THEN 1 END) END), 0) AS inSkuMother, COALESCE(SUM(CASE WHEN 모자='N' THEN (CASE WHEN IBQTY>0 THEN 1 END) END), 0) AS inSkuChild, COALESCE(SUM(IBQTY), 0) AS inEa, COALESCE(SUM(IB_AMT), 0) AS inAmt, COALESCE(CASE WHEN SUM(CASE WHEN EXPCTQTY>0 THEN 1 END)=0 THEN 0 ELSE ROUND( SUM(CASE WHEN IBQTY>0 THEN 1 END) / SUM(CASE WHEN EXPCTQTY>0 THEN 1 END) * 100 ,1) END, 0) AS inSkuRate, COALESCE(CASE WHEN SUM(EXPCTQTY)=0 THEN 0 ELSE ROUND(SUM(IBQTY)/SUM(EXPCTQTY)*100,1) END, 0) AS inEaRate, /* ===== 적치 PUT ===== */ COALESCE(SUM(CASE WHEN 모자='Y' THEN (CASE WHEN CNFRMQTY>0 THEN 1 END) END), 0) AS putSkuMother, COALESCE(SUM(CASE WHEN 모자='N' THEN (CASE WHEN CNFRMQTY>0 THEN 1 END) END), 0) AS putSkuChild, COALESCE(SUM(CNFRMQTY), 0) AS putEa, COALESCE(SUM(CNFM_AMT), 0) AS putAmt, COALESCE(CASE WHEN SUM(CASE WHEN EXPCTQTY>0 THEN 1 END)=0 THEN 0 ELSE ROUND( SUM(CASE WHEN CNFRMQTY>0 THEN 1 END) / SUM(CASE WHEN EXPCTQTY>0 THEN 1 END) * 100 ,1) END, 0) AS putSkuRate, COALESCE(CASE WHEN SUM(EXPCTQTY)=0 THEN 0 ELSE ROUND(SUM(CNFRMQTY)/SUM(EXPCTQTY)*100,1) END, 0) AS putEaRate, COALESCE(MAX(UPDATEDATE), '00000000') AS UPDATEDATE, COALESCE(MAX(입고번호), '') AS IBHDKEY, COALESCE(MAX(IBDTKEY), '') AS IBDTKEY FROM BASE WHERE 1=1 GROUP BY 입고번호, 입고유형
#{item}
#{item}
AND A.ASRTYN = #{asrtyn}
AND A.CLOSEYN = #{closeyn}

mapper.select:
