mapper.sql:
/* wms-inbound-iborderreport-sql-oracle.xml - selectIbDetailsql - 입고현황 - 상세현황 - 입고 상세 현황 조회 SQL */ SELECT * FROM ( SELECT A.CTKEY , L.CTNM , A.OWKEY , A.IBHDKEY , A.IBDTKEY , B.IBHDTYPECD , B.IBEXPCTDATE , CASE WHEN B.IBHDTYPECD = '30' THEN B.ACNM ELSE '' END AS OB_CTNM , CASE WHEN B.IBHDTYPECD != '30' THEN B.ACNM ELSE '' END AS ACNM , B.EXTORDERKEY , C.ACKEY AS IC_ACKEY , D.ACNM AS IC_ACNM , COALESCE(E.ASRTMASICKEY, A.ICKEY) AS ASRTMASICKEY , COALESCE(G.ICNM, C.ICNM) AS ASRTMASICNM , CASE WHEN E.ASRTDTICKEY IS NOT NULL THEN A.ICKEY END AS ASRTDTICKEY , CASE WHEN E.ASRTDTICKEY IS NOT NULL THEN C.ICNM END AS ASRTDTICNM , CASE WHEN EXISTS ( SELECT 1 FROM TWORK_MST_ASRT WHERE CTKEY = A.CTKEY AND OWKEY = A.OWKEY AND (A.ICKEY = ASRTMASICKEY OR A.ICKEY = ASRTDTICKEY) ) THEN 'Y' ELSE 'N' END AS ASRTYN , CTG3.CTGNM AS LV1_CTGNM , CTG2.CTGNM AS LV2_CTGNM , CTG1.CTGNM AS LV3_CTGNM , A.UOM , COALESCE(A.INITQTY, 0) AS INITQTY , CASE WHEN I.ICUNITQTY IS NULL THEN 0 WHEN A.INITQTY > 0 THEN ROUND(A.INITQTY / COALESCE(I.ICUNITQTY, 1), 2) ELSE COALESCE(A.INITQTY, 0) END AS INITQTY_INN , CASE WHEN J.ICUNITQTY IS NULL THEN 0 WHEN A.INITQTY > 0 THEN ROUND(A.INITQTY / COALESCE(J.ICUNITQTY, 1), 2) ELSE COALESCE(A.INITQTY, 0) END AS INITQTY_CTN , CASE WHEN J.ICUNITQTY IS NULL THEN 0 WHEN A.INITQTY > 0 THEN ROUND(A.INITQTY / (COALESCE(J.ICUNITQTY, 1) * CASE COALESCE(J.CPPQTY, 0) WHEN 0 THEN 1 ELSE J.CPPQTY END), 2) ELSE COALESCE(A.INITQTY, 0) END AS INITQTY_PLT , COALESCE(A.INITQTY * C.SLPRC, 0) AS INITQTY_SLPRC , COALESCE(A.EXPCTQTY, 0) AS EXPCTQTY , CASE WHEN I.ICUNITQTY IS NULL THEN 0 WHEN A.EXPCTQTY > 0 THEN ROUND(A.EXPCTQTY / COALESCE(I.ICUNITQTY, 1), 2) ELSE COALESCE(A.EXPCTQTY, 0) END AS EXPCTQTY_INN , CASE WHEN J.ICUNITQTY IS NULL THEN 0 WHEN A.EXPCTQTY > 0 THEN ROUND(A.EXPCTQTY / COALESCE(J.ICUNITQTY, 1), 2) ELSE COALESCE(A.EXPCTQTY, 0) END AS EXPCTQTY_CTN , CASE WHEN J.ICUNITQTY IS NULL THEN 0 WHEN A.EXPCTQTY > 0 THEN ROUND(A.EXPCTQTY / (COALESCE(J.ICUNITQTY, 1) * CASE COALESCE(J.CPPQTY, 0) WHEN 0 THEN 1 ELSE J.CPPQTY END), 2) ELSE COALESCE(A.EXPCTQTY, 0) END AS EXPCTQTY_PLT , COALESCE(A.EXPCTQTY * C.SLPRC, 0) AS EXPCTQTY_SLPRC , COALESCE(A.IBQTY, 0) AS IBQTY , CASE WHEN I.ICUNITQTY IS NULL THEN 0 WHEN A.IBQTY > 0 THEN ROUND(A.IBQTY / COALESCE(I.ICUNITQTY, 1), 2) ELSE COALESCE(A.IBQTY, 0) END AS IBQTY_INN , CASE WHEN J.ICUNITQTY IS NULL THEN 0 WHEN A.IBQTY > 0 THEN ROUND(A.IBQTY / COALESCE(J.ICUNITQTY, 1), 2) ELSE COALESCE(A.IBQTY, 0) END AS IBQTY_CTN , CASE WHEN J.ICUNITQTY IS NULL THEN 0 WHEN A.IBQTY > 0 THEN ROUND(A.IBQTY / (COALESCE(J.ICUNITQTY, 1) * CASE COALESCE(J.CPPQTY, 0) WHEN 0 THEN 1 ELSE J.CPPQTY END), 2) ELSE COALESCE(A.IBQTY, 0) END AS IBQTY_PLT , COALESCE(A.IBQTY * C.SLPRC, 0) AS IBQTY_SLPRC , COALESCE(A.CNFRMQTY, 0) AS CNFRMQTY , CASE WHEN I.ICUNITQTY IS NULL THEN 0 WHEN A.CNFRMQTY > 0 THEN ROUND(A.CNFRMQTY / COALESCE(I.ICUNITQTY, 1), 2) ELSE COALESCE(A.CNFRMQTY, 0) END AS CNFRMQTY_INN , CASE WHEN J.ICUNITQTY IS NULL THEN 0 WHEN A.CNFRMQTY > 0 THEN ROUND(A.CNFRMQTY / COALESCE(J.ICUNITQTY, 1), 2) ELSE COALESCE(A.CNFRMQTY, 0) END AS CNFRMQTY_CTN , CASE WHEN J.ICUNITQTY IS NULL THEN 0 WHEN A.CNFRMQTY > 0 THEN ROUND(A.CNFRMQTY / (COALESCE(J.ICUNITQTY, 1) * CASE COALESCE(J.CPPQTY, 0) WHEN 0 THEN 1 ELSE J.CPPQTY END), 2) ELSE COALESCE(A.CNFRMQTY, 0) END AS CNFRMQTY_PLT , COALESCE(A.CNFRMQTY * C.SLPRC, 0) AS CNFRMQTY_SLPRC , CASE WHEN A.IBDTSTATUSCD = '91' THEN 'Y' ELSE 'N' END AS CLOSEYN , A.IBDTSTATUSCD , B.ACKEY , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY FROM TWORK_INFO_IB_DT A INNER JOIN TWORK_INFO_IB_HD B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.IBHDKEY = B.IBHDKEY INNER JOIN TWORK_MST_IC C ON A.CTKEY = C.CTKEY AND A.OWKEY = C.OWKEY AND A.ICKEY = C.ICKEY LEFT OUTER JOIN TWORK_MST_AC D ON A.CTKEY = D.CTKEY AND C.ACKEY = D.ACKEY LEFT OUTER JOIN TWORK_MST_ASRT E ON A.CTKEY = E.CTKEY AND A.OWKEY = E.OWKEY AND A.ICKEY = E.ASRTDTICKEY LEFT OUTER JOIN TWORK_MST_IC G ON A.CTKEY = G.CTKEY AND A.OWKEY = G.OWKEY AND E.ASRTMASICKEY = G.ICKEY INNER JOIN TWORK_MST_CTG CTG1 ON A.CTKEY = CTG1.CTKEY AND A.OWKEY = CTG1.OWKEY AND C.CTGKEY = CTG1.CTGKEY AND CTG1.CTGLV = '3' INNER JOIN TWORK_MST_CTG CTG2 ON CTG1.CTKEY = CTG2.CTKEY AND CTG1.OWKEY = CTG2.OWKEY AND CTG1.UPRCTGKEY = CTG2.CTGKEY AND CTG2.CTGLV = '2' INNER JOIN TWORK_MST_CTG CTG3 ON CTG2.CTKEY = CTG3.CTKEY AND CTG2.OWKEY = CTG3.OWKEY AND CTG2.UPRCTGKEY = CTG3.CTGKEY AND CTG3.CTGLV = '1' LEFT OUTER JOIN TWORK_MST_ICUTXTYPE I ON A.CTKEY = I.CTKEY AND A.OWKEY = I.OWKEY AND C.ICUNITKEY = I.ICUNITKEY AND I.ICUNITTYPECD = 'INN' LEFT OUTER JOIN TWORK_MST_ICUTXTYPE J ON A.CTKEY = J.CTKEY AND A.OWKEY = J.OWKEY AND C.ICUNITKEY = J.ICUNITKEY AND J.ICUNITTYPECD = 'CTN' INNER JOIN TWORK_MST_CT L ON A.CTKEY = L.CTKEY WHERE A.CTKEY = #{ctkey} AND A.OWKEY = #{owkey} ) A WHERE 1=1
AND A.IBEXPCTDATE BETWEEN #{ibexpctdateFrom} || '000000' AND #{ibexpctdateTo} || '235959'
AND A.IBHDTYPECD = #{ibhdtypecd}
AND A.IBDTSTATUSCD = #{ibstatuscd}
AND A.IBHDKEY = #{ibhdkey}
AND A.EXTORDERKEY = #{extorderkey}
AND A.ACKEY = #{ackey}
#{item}
#{item}
AND A.ASRTYN = #{asrtyn}
AND A.CLOSEYN = #{closeyn}

